class Solution {
public:
    vector<vector<string>> findDuplicate(vector<string>& paths) {
        unordered_map<string, vector<string>> contentToPaths;
        for (const string& path : paths) {
            stringstream ss(path);
            string root;
            ss >> root;
            string file;
            while (ss >> file) {
                int left = file.find('(');
                int right = file.find(')');
                string content = file.substr(left + 1, right - left - 1);
                string filePath = root + "/" + file.substr(0, left);
                contentToPaths[content].push_back(filePath);
            }
        }
        vector<vector<string>> result;
        for (const auto& pair : contentToPaths) {
            if (pair.second.size() > 1) {
                result.push_back(pair.second);
            }
        }
        return result;
    }
};
